#include <bits/stdc++.h>
using namespace std;
int n,t[101],dp_up[101],dp_down[101];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>t[i];
    //for(int i=1;i<=n;i++)cout<<t[i]<<' ';
    //cout<<endl;
    for(int i=1;i<=n;i++)dp_up[i]=dp_down[i]=1;
    //cout<<1<<' ';
    for(int i=2;i<=n;i++){
    	for(int j=1;j<i;j++)
            if(t[j]<t[i])dp_up[i]=max(dp_up[i],dp_up[j]+1);
        //cout<<dp_up[i]<<' '; 
	}
    //cout<<endl;
    for(int i=n-1;i;i--)
        for(int j=n;j>i;j--)
            if(t[j]<t[i])dp_down[i]=max(dp_down[i],dp_down[j]+1);
    //for(int i=1;i<=n;i++)cout<<dp_down[i]<<' ';
    //cout<<endl;
    int ans=-1;
    for(int i=1;i<=n;i++)ans=max(ans,dp_up[i]+dp_down[i]-1);
    cout<<n-ans;
    return 0;
}
